from services.orders.repository import load_orders
from services.statements.exporter import charge_rows, payout_line_rows, refund_line_rows


def test_charge_rows_cover_all_orders():
    orders = load_orders()
    rows = charge_rows(orders)
    assert len(rows) == len(orders)
    assert set(rows[0]) == {"order_id", "charged_at", "status", "charged_cents"}


def test_refund_lines_only_for_cancelled_orders():
    orders = load_orders()
    cancelled = {o.id for o in orders if o.status == "cancelled"}
    rows = refund_line_rows(orders)
    assert rows and {r["order_id"] for r in rows} == cancelled


def test_payout_lines_only_for_fulfilled_orders():
    orders = load_orders()
    fulfilled = {o.id for o in orders if o.status == "fulfilled"}
    rows = payout_line_rows(orders)
    assert rows and {r["order_id"] for r in rows} == fulfilled
    assert any(r["payee"] == "platform" for r in rows)

